export async function seedKimiAgents(): Promise<void> {
  try {
    const existingAgents = await db.select({ id: kimiAgentsTable.id, name: kimiAgentsTable.name }).from(kimiAgentsTable);
    const existingMap = new Map(existingAgents.map((a) => [a.name, a.id]));

    for (const agent of AGENTS) {
      const existingId = existingMap.get(agent.name);
      if (existingId) {
        await db.update(kimiAgentsTable).set({
          systemPrompt: agent.systemPrompt,
          description: agent.description,
          category: agent.category,
          icon: agent.icon,
        }).where(eq(kimiAgentsTable.id, existingId));
      }
    }

    const newAgents = AGENTS.filter((a) => !existingMap.has(a.name));

    if (newAgents.length === 0) {
      logger.info("kimi_agents_synced", { updated: existingAgents.length });
      return;
    }

    const values = newAgents.map((a, i) => ({
      name: a.name,
      description: a.description,
      category: a.category,
      systemPrompt: a.systemPrompt,
      defaultModel: a.defaultModel || "kimi-k2.5",
      icon: a.icon,
      isActive: true,
      sortOrder: existingAgents.length + i + 1,
    }));

    await db.insert(kimiAgentsTable).values(values);
    logger.info("kimi_agents_seeded", { count: values.length, total: existingAgents.length + values.length });
  } catch (error: any) {
    logger.error("kimi_agents_seed_failed", { error: error?.message });
  }
}
